queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasMobile_Banking_App ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :MobileBankingApps } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?app_version ?feature_value WHERE {
  ?mobile_banking_app_features a :Mobile_Banking_App_Features .
  ?mobile_banking_app a :MobileBankingApps .
  ?mobile_banking_app_features p:hasMobile_Banking_App ?mobile_banking_app .
  ?features a :Features .
  ?mobile_banking_app_features p:hasFeatures ?features .
  ?mobile_banking_app p:app_version ?app_version .
  ?features p:feature_value ?feature_value .
} }
  collective: { SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasMobile_Banking_App ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :MobileBankingApps } }
  FILTER(?nf = ?total)
} }
}
